#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, M; scanf("%d %d", &N, &M);
        int *a = (int*)malloc(N * sizeof(int));
        int maxVal = 0;
        for(int i=0;i<N;i++){
            scanf("%d", &a[i]);
            if(a[i] > maxVal) maxVal = a[i];
        }
        long long total = 0;
        for(int i=0;i<N;i++) total += (long long)(maxVal - a[i]);
        long long ans = (total + M - 1) / M;
        printf("%lld\n", ans);
        free(a);
    }
    return 0;
}

